args.sparql:
SELECT ?continent ?continentLabel ?mammal ?mammalLabel ?weight WHERE {
  ?continent wdt:P31 wd:Q515 .
  ?country wdt:P30 ?continent .
  ?mammal wdt:P31 wd:Q146 ;
          wdt:P367 wd:Q927416 ;
          wdt:P1887 ?country ;
          wdt:P2046 ?weight .
  ?mammal rdfs:label ?mammalLabel .
  ?continent rdfs:label ?continentLabel .
  FILTER (LANG(?mammalLabel) = 'en') .
  FILTER (LANG(?continentLabel) = 'en') .
  FILTER NOT EXISTS {
    ?country2 wdt:P30 ?continent .
    ?mammal2 wdt:P31 wd:Q146 ;
             wdt:P367 wd:Q927416 ;
             wdt:P1887 ?country2 ;
             wdt:P2046 ?weight2 .
    FILTER (?weight2 > ?weight)
  }
}

SELECT ?continent ?continentLabel ?mammal ?mammalLabel ?weight WHERE {
  {
    SELECT ?continent (MAX(?weight) AS ?maxWeight)
    WHERE {
      ?continent wdt:P31 wd:Q515 .
      ?country wdt:P30 ?continent .
      ?mammal wdt:P31 wd:Q146 ;
              wdt:P367 wd:Q927416 ;
              wdt:P1887 ?country ;
              wdt:P2046 ?weight .
    }
    GROUP BY ?continent
  }
  ?continent wdt:P31 wd:Q515 .
  ?country wdt:P30 ?continent .
  ?mammal wdt:P31 wd:Q146 ;
          wdt:P367 wd:Q927416 ;
          wdt:P1887 ?country ;
          wdt:P2046 ?weight .
  FILTER(?weight = ?maxWeight) .
  ?mammal rdfs:label ?mammalLabel .
  ?continent rdfs:label ?continentLabel .
  FILTER (LANG(?mammalLabel) = 'en') .
  FILTER (LANG(?continentLabel) = 'en') .
}

SELECT ?continent ?continentLabel ?mammal ?mammalLabel ?weightValue WHERE {
  {
    SELECT ?continent (MAX(?weightVal) AS ?maxWeight)
    WHERE {
      ?continent wdt:P31 wd:Q515 .
      ?country wdt:P30 ?continent .
      ?mammal wdt:P31 wd:Q146 ;
              wdt:P367 wd:Q927416 ;
              wdt:P1887 ?country ;
              wdt:P2046 ?weightStat .
      ?weightStat psn:P2046 ?weightVal .
    }
    GROUP BY ?continent
  }
  ?continent wdt:P31 wd:Q515 .
  ?country wdt:P30 ?continent .
  ?mammal wdt:P31 wd:Q146 ;
          wdt:P367 wd:Q927416 ;
          wdt:P1887 ?country ;
          wdt:P2046 ?weightStat .
  ?weightStat psn:P2046 ?weightValue .
  FILTER(?weightValue = ?maxWeight) .
  ?mammal rdfs:label ?mammalLabel .
  ?continent rdfs:label ?continentLabel .
  FILTER (LANG(?mammalLabel) = 'en') .
  FILTER (LANG(?continentLabel) = 'en') .
}
